import luigi
import csv
import json
from datetime import date

# ─────────────────────────────────────────
# Step 1: Download raw data
# ─────────────────────────────────────────
class DownloadRawData(luigi.Task):
    """Simulates downloading raw transaction data for a given date."""
    date = luigi.DateParameter()

    def output(self):
        return luigi.LocalTarget(f"data/raw/transactions_{self.date}.csv")

    def run(self):
        # In production, this would call an API or copy from a source system
        rows = [
            ["user_id", "amount", "category"],
            ["u001", "49.99", "electronics"],
            ["u002", "12.50", "food"],
            ["u001", "3.00", "food"],
            ["u003", "199.00", "electronics"],
        ]
        self.output().makedirs()
        with self.output().open("w") as f:
            writer = csv.writer(f)
            writer.writerows(rows)


# ─────────────────────────────────────────
# Step 2: Clean and validate the data
# ─────────────────────────────────────────
class CleanData(luigi.Task):
    date = luigi.DateParameter()

    def requires(self):
        return DownloadRawData(date=self.date)

    def output(self):
        return luigi.LocalTarget(f"data/clean/transactions_{self.date}.csv")

    def run(self):
        self.output().makedirs()
        with self.input().open("r") as infile, self.output().open("w") as outfile:
            reader = csv.DictReader(infile)
            writer = csv.DictWriter(outfile, fieldnames=["user_id", "amount", "category"])
            writer.writeheader()
            for row in reader:
                try:
                    amount = float(row["amount"])
                    if amount > 0:  # Drop invalid rows
                        row["amount"] = f"{amount:.2f}"
                        writer.writerow(row)
                except ValueError:
                    pass  # Skip rows with bad amounts


# ─────────────────────────────────────────
# Step 3: Aggregate by category
# ─────────────────────────────────────────
class AggregateByCategory(luigi.Task):
    date = luigi.DateParameter()

    def requires(self):
        return CleanData(date=self.date)

    def output(self):
        return luigi.LocalTarget(f"data/aggregated/by_category_{self.date}.json")

    def run(self):
        totals = {}
        with self.input().open("r") as f:
            reader = csv.DictReader(f)
            for row in reader:
                cat = row["category"]
                totals[cat] = totals.get(cat, 0) + float(row["amount"])

        self.output().makedirs()
        with self.output().open("w") as f:
            json.dump(totals, f, indent=2)


# ─────────────────────────────────────────
# Step 4: Generate final report
# ─────────────────────────────────────────
class GenerateReport(luigi.Task):
    date = luigi.DateParameter()

    def requires(self):
        return AggregateByCategory(date=self.date)

    def output(self):
        return luigi.LocalTarget(f"reports/report_{self.date}.txt")

    def run(self):
        with self.input().open("r") as f:
            totals = json.load(f)

        self.output().makedirs()
        with self.output().open("w") as f:
            f.write(f"Daily Transaction Report — {self.date}\n")
            f.write("=" * 40 + "\n")
            for category, total in sorted(totals.items()):
                f.write(f"  {category:20s} ${total:>10.2f}\n")
            f.write("=" * 40 + "\n")
            f.write(f"  {'TOTAL':20s} ${sum(totals.values()):>10.2f}\n")


# ─────────────────────────────────────────
# Run from command line:
# python -m luigi --module pipeline GenerateReport --date 2024-01-15 --local-scheduler
