import luigi
import luigi.contrib.s3
from datetime import date, timedelta

class RawEventsS3(luigi.ExternalTask):
    """Raw clickstream events deposited by the ingestion service."""
    date = luigi.DateParameter()

    def output(self):
        return luigi.contrib.s3.S3Target(
            f"s3://data-lake/raw/events/dt={self.date}/part-*.parquet"
        )


class FilterValidEvents(luigi.Task):
    date = luigi.DateParameter()

    def requires(self):
        return RawEventsS3(date=self.date)

    def output(self):
        return luigi.contrib.s3.S3Target(
            f"s3://data-lake/staging/events/dt={self.date}/_SUCCESS"
        )

    def run(self):
        # PySpark job, subprocess call, or EMR step submission
        import subprocess
        subprocess.run([
            "spark-submit",
            "--master", "yarn",
            "jobs/filter_events.py",
            "--date", str(self.date),
        ], check=True)
        # Write _SUCCESS marker after the job completes
        with self.output().open("w") as f:
            f.write("done")


class ComputeUserFeatures(luigi.Task):
    date = luigi.DateParameter()

    def requires(self):
        # Requires the last 7 days of filtered events for rolling features
        return [FilterValidEvents(date=self.date - timedelta(days=i))
                for i in range(7)]

    def output(self):
        return luigi.contrib.s3.S3Target(
            f"s3://data-lake/features/user_features/dt={self.date}/_SUCCESS"
        )

    def run(self):
        import subprocess
        subprocess.run([
            "spark-submit", "jobs/compute_user_features.py",
            "--date", str(self.date)
        ], check=True)
        with self.output().open("w") as f:
            f.write("done")


class TrainModel(luigi.Task):
